                HorizontalDivider(color = Color.DarkGray)
            }
        }
    }

    // --- HIJACK OVERLAY ---
    SideEffect {
        if (isHijackActive) {
            DynamicEntry.overlayContent = { 
                Box(modifier = Modifier.fillMaxSize()) {
                    stickerBounds.forEach { (name, rect) ->
